while (1) {
  c = getchar();       // blocks via yield
  if (c == 0x03) {     // Ctrl+C detected!
    // Send SIGINT to shell (self)
    pending_signals[cur_pid] |= (1 << SIGINT);
    return;
  }
  // ... normal char handling ...
}

for (sig = 1; sig < NSIG; sig++) {
  if (pending & (1 << sig)) {   // sig=2 ✓
    clear bit
    check signal_actions[2][2]
    → sa_handler = 0x40001dc0  // registered!
    → deliver_signal(pid, sig, sa, tf)
  }
}

tcb_set_state(7, TSTATE_DEAD);
if (old_state == TSTATE_READY)
  tqueue_remove(NUM_IDS, 7);
// Don't call thread_exit() here —
// shell is currently running,
// child cleaned up on next schedule

void sigint_test(void) {
  printf("Starting infinite loop...\n");
  printf("Press Ctrl+C to stop\n");
  int i = 0;
  while (1) {
    printf("Hello World! (%d)\n", i++);
    // Runs until shell kills it
  }
}

void sigint_handler(int sig) {
  printf("\n[SHELL] Ctrl+C: "
         "terminating process %d\n",
         fg_pid);
  if (fg_pid > 0) {
    kill(fg_pid, SIGKILL);  // kill child
    fg_pid = 0;
  }
}

static int fg_pid = 0;  // global in shell

// When spawning child:
fg_pid = spawn(sigint_test);

// In SIGINT handler:
kill(fg_pid, SIGKILL);
fg_pid = 0;   // no more foreground
